// Aggregate message stats from last 60 min of message log
const messages = $('Read Message Log').all();

let totalMessages = 0;
let totalResponseTime = 0;
let responseCount = 0;
const sentimentKeywords = {
  positive: ['thank', 'great', 'awesome', 'happy', 'perfect', 'excellent', 'love', 'appreciate'],
  negative: ['angry', 'frustrated', 'terrible', 'worst', 'hate', 'disappointed', 'awful', 'useless'],
  neutral: [],
};
let posCount = 0;
let negCount = 0;
const agentStats = {};

for (const item of messages) {
  const d = item.json;
  totalMessages++;

  // Response time (if available)
  if (d['Response Time'] || d.response_time_seconds) {
    const rt = parseFloat(d['Response Time'] || d.response_time_seconds);
    if (!isNaN(rt)) {
      totalResponseTime += rt;
      responseCount++;
    }
  }

  // Sentiment keyword scan
  const text = ((d.Message || d.Body || d.message || '') + '').toLowerCase();
  for (const kw of sentimentKeywords.positive) {
    if (text.includes(kw)) { posCount++; break; }
  }
  for (const kw of sentimentKeywords.negative) {
    if (text.includes(kw)) { negCount++; break; }
  }

  // Per-agent stats
  const agent = d.Agent || d.agent_name || 'Unassigned';
  if (!agentStats[agent]) {
    agentStats[agent] = { messages: 0, resolved: 0 };
  }
  agentStats[agent].messages++;
  if ((d.Status || '').toLowerCase() === 'resolved') {
    agentStats[agent].resolved++;
  }
}

const avgResponseTime = responseCount > 0
  ? (totalResponseTime / responseCount).toFixed(1)
  : 'N/A';
const sentimentScore = totalMessages > 0
  ? ((posCount - negCount) / totalMessages).toFixed(3)
  : '0';
const resolutionRate = totalMessages > 0
  ? (Object.values(agentStats).reduce((s, a) => s + a.resolved, 0) / totalMessages * 100).toFixed(1)
  : '0';

const hasCriticalIssues = parseFloat(sentimentScore) < -0.3
  || parseFloat(avgResponseTime !== 'N/A' ? avgResponseTime : '0') > 300
  || parseFloat(resolutionRate) < 30;

return {
  json: {
    totalMessages,
    avgResponseTime: avgResponseTime === 'N/A' ? avgResponseTime : parseFloat(avgResponseTime),
    sentimentScore: parseFloat(sentimentScore),
    positiveCount: posCount,
    negativeCount: negCount,
    resolutionRate: parseFloat(resolutionRate),
    agentStats,
    hasCriticalIssues,
    analyzedAt: new Date().toISOString(),
  }
};

